c
// Page Table Entry (Standard x86)
typedef struct {
uint32_t pfn : 20;      // Physical Frame Number
uint32_t valid : 1;    // Present bit
uint32_t readable : 1;
uint32_t writable : 1;
uint32_t dirty : 1;    // Written since last load
uint32_t ref : 1;      // Used for LRU/Clock
uint32_t unused : 7;   // OS Defined / Reserved
} pte_t;

// Replacement Context
typedef enum {
REPL_FIFO,
REPL_LRU,
REPL_CLOCK,
REPL_OPTIMAL
} repl_algo_t;
